scrollTopAfterClose=$cmhp_jq(document).scrollTop();$cmhp_jq('html, body').css({overflow:'hidden',height:'100%'});$cmhp_jq('<div id="exphp_mask"/>').css({position:'fixed',left:0,right:0,top:0,bottom:0,background:'rgba(255,255,255,1)',zIndex:999999999999,display:'flex','align-items':'center','justify-content':'center',lineHeight:1}).appendTo('body');$cmhp_jq('<div id="exphp_overlay" class="exphp_overlay_firstinfo"/>').css({background:'#fff',border:'1px solid #DDDDDD','box-shadow':'0px 0px 7px #bbb','height':'80vh',width:'600px','max-width':'100vw','box-sizing':'border-box',overflow:'hidden'}).appendTo('#exphp_mask');$cmhp_jq('#exphp_overlay').append('<div id="exphp_header" style="border-bottom: 2px solid #c9c9ca; position: relative; padding: 10px;"><h1 style="margin: 0; font-size: 36px; line-height: 1; text-decoration: none;">Erstinformationen</h1></div>');$cmhp_jq('#exphp_overlay').append('<div id="exphp_overlaycontentcontainer" style="position: relative; border: 0 none; width: 100%; box-sizing: border-box; height: calc( 80vh - 220px ); overflow: hidden; padding: 0;"></div>');$cmhp_jq('#exphp_overlaycontentcontainer').after('<div id="exphp_buttoncontainer" style="text-align: center; border-top: 2px solid #c9c9ca;"><label style="text-align: center; display: block; margin-top: 35px; margin-bottom: 25px;"><input type="checkbox" name="cb_firstinfo_accept" style="margin-right: 5px;">Ich habe die Erstinformation gelesen und gespeichert</label></div>');$cmhp_jq('#exphp_buttoncontainer').append('<a class="bigsubmitbutton save_pdf" href="https://config.digidor.de/content/erstinformation-13922e59.pdf" target="_blank">Erstinformation speichern</a>');$cmhp_jq('#exphp_buttoncontainer').append('<a class="bigsubmitbutton close_overlay" href="#" onclick="return exphpCloseOverlay();">weiter</a>');$cmhp_jq('#exphp_overlay').find('.bigsubmitbutton').css({paddingTop:'12px',paddingBottom:'12px',paddingLeft:'15px',paddingRight:'15px',fontSize:'16px',marginTop:'15px',});$cmhp_jq('#exphp_overlay').find('.bigsubmitbutton.save_pdf').css({background:'rgb(242, 242, 242)',border:'1px solid rgb(201, 201, 202)',color:'rgb(51, 51, 51)',float:'left',marginLeft:'20px'});$cmhp_jq('#exphp_overlay').find('.bigsubmitbutton.close_overlay').css({float:'right',marginRight:'20px'});var data="<!DOCTYPE html>\n<!-- Generated by PHPWord -->\n<html>\n<head>\n<meta charset=\"UTF-8\" \/>\n<title>Erstinformation<\/title>\n<meta name=\"title\" content=\"Erstinformation\" \/>\n<style>\n* {font-family: Arial; font-size: 10pt;}\na.NoteRef {text-decoration: none;}\nhr {height: 1px; padding: 0; margin: 1em 0; border: 0; border-top: 1px solid #CCC;}\ntable {border: 1px solid black; border-spacing: 0px; width : 100%;}\ntd {border: 1px solid black;}\nh3 {font-weight: bold;}\nh1 {font-size: 24pt;}\n<\/style>\n<\/head>\n<body>\n\n<h1>Erstinformation<\/h1>\n\n<p>Kundeninformation zur Erf\u00fcllung der gesetzlichen Informationspflicht<\/p>\n\n<p><a target=\"_blank\" href=\"\/eh-content\/erstinformation-13922e59.pdf\">[Erstinformation als PDF sichern]<\/a><\/p>\n\n<h3>1. Name, Anschrift und Kontaktdaten:<\/h3>\n<p>Havel Spree Finanz<br\/>Sebastian Kr\u00fcger<br\/>Dolziger Strasse 51<br\/>10247 Berlin<br\/>Tel.: +49-151-28937141<br\/>E-Mail: Buero@SpreeFinanz.de<\/p>\n\n<h3>2. T\u00e4tigkeitsart:<\/h3>\n<p>Versicherungsmakler mit einer Erlaubnis nach \u00a7 34 d Abs. 1 der Gewerbeordnung. (GewO)<br\/>Immobiliardarlehensvermittler mit einer Erlaubnis nach \u00a7 34 i Abs. 1 Satz 1 der Gewerbeordnung. (GewO)<\/p>\n\n<h3>3. Gemeinsame Registerstelle nach \u00a7 11 a Abs. 1 GewO:<\/h3>\n<p>Vermittlerregisternummer Versicherungsvermittlung: D-GIHP-4XO0C-76<br\/>Vermittlerregisternummer Immobiliardarlehensvermittlung: D-W-107-3JA4-53<br\/><\/p>\n<p>Deutsche Industrie- und Handelskammer (DIHK)<br\/>Breite Stra\u00dfe 29<br\/>10178 Berlin<br\/>Telefon: 0180 600 58 50 (0,20 Euro\/Anruf)<br\/><a target=\"_blank\" href=\"https:\/\/www.vermittlerregister.info\">www.vermittlerregister.info<\/a><\/p>\n\n<h3>4. Erlaubnisbeh\u00f6rde:<\/h3>\n<p>Versicherungsvermittlung: Industrie- und Handelskammer zu Berlin, Fasanenstra\u00dfe 85, 10623 Berlin<\/p>\n<p>Immobiliardarlehensvermittlung: BA Friedrichshain-Kreuzberg von Berlin Ordnungs- und Gewerbeamt, Petersburger Str. 37, 10247 Berlin<\/p>\n\n<h3>5. Schlichtungsstellen:<\/h3>\n<p>Schlichtungsstelle f\u00fcr gewerbliche Versicherungs-, Anlage- und Kreditvermittlung<br\/>Barmbeker Stra\u00dfe 2, 2. OG, 22303 Hamburg<\/p>\n\n<h3>6. Beratung bei der Versicherungsvermittlung:<\/h3>\n<p>Im Zuge der Vermittlung bietet Sebastian Kr\u00fcger eine Beratung gem\u00e4\u00df den gesetzlichen Vorgaben an.<\/p>\n\n<h3>7. Informationen \u00fcber Art und Quelle der Verg\u00fctung als Versicherungsmakler:<\/h3>\n<p>Die Verg\u00fctung der T\u00e4tigkeit erfolgt als: <br\/>- konkret vereinbarte Zahlung durch den Kunden oder als<br\/>- in der Versicherungspr\u00e4mie enthaltene Provision, die vom jeweiligen Versicherungsunternehmen ausgezahlt wird oder als<br\/>- Kombination aus beidem.<br\/>Dies ist jeweils abh\u00e4ngig von den W\u00fcnschen und Bed\u00fcrfnissen des Kunden und den Versicherungsprodukten, welche eventuell vermittelt werden.<\/p>\n\n<h3>8. Leistungsentgelt \/ Kosten bei der Immobiliardarlehensvermittlung:<\/h3>\n<p>Der Vermittler erh\u00e4lt ein Leistungsentgelt f\u00fcr die erfolgreiche Darlehensvermittlung vom Darlehensgeber.<br\/>Die H\u00f6he dieser Verg\u00fctung kann sich insbesondere ergeben aus: der Bruttodarlehenssumme, Zinszahlungen, Pr\u00e4mien. Wie hoch die Verg\u00fctung des Vermittlers konkret sein wird, steht zum Zeitpunkt der Aush\u00e4ndigung dieser Information noch nicht fest. Er wird Ihnen zu einem sp\u00e4teren Zeitpunkt auf dem sog. ESIS-Merkblatt mitgeteilt, welches Sie rechtzeitig vor Vertragsschluss ausgeh\u00e4ndigt bekommen. Es k\u00f6nnen weitere variable Verg\u00fctungen hinzukommen, die sich an qualitativen Merkmalen bemessen.<\/p>\n\n<h3>9. Produktauswahlpalette bei der Immobiliardarlehensvermittlung:<\/h3>\n<p>Der Vermittler wird unabh\u00e4ngig t\u00e4tig.<\/p>\n\n<h3>10. Beratung bei der Immobiliardarlehensvermittlung:<\/h3>\n<p>Die T\u00e4tigkeit als Immobiliardarlehensvermittler beinhaltet auch Beratung.<\/p>\n\n<\/body>\n<\/html>\n"
